// Normalize payload: body fields + binary attachment
const b = $input.first().json.body || $input.first().json;
const binary = $input.first().binary || {};

// Find the first binary property (FormData field 'data')
const binaryKey = Object.keys(binary)[0];
const file = binaryKey ? binary[binaryKey] : null;

// Split emails by comma/semicolon → clean array
const emails = String(b.email || '')
  .split(/[,;]+/)
  .map(e => e.trim())
  .filter(e => /@/.test(e));

return [{
  json: {
    emails_to: emails.join(', '),
    emails_array: emails,
    recipients_count: emails.length,
    subject: b.subject || 'תלוש שכר',
    body: b.body || '',
    body_html: b.body_html || `<div dir="rtl">${b.body || ''}</div>`,
    scope: b.scope || 'employee',
    schedule_mode: b.schedule_mode || 'now',
    send_at: b.send_at || 'now',
    send_at_utc: b.send_at_utc || 'now',
    employee_number: b.employee_number || '',
    name: b.name || '',
    department: b.department || '',
    category: b.category || '',
    month: b.month || '',
    count: b.count || '',
    filename: file ? file.fileName : 'attachment.pdf',
  },
  binary: binary
}];
